public class DiceGame {
    public int rollDie(int numFaces) {
        return (int)(Math.random() * numFaces) + 1;
    }

    public int simulateGame(int numRounds, int targetSum) {
        int hits = 0;
        for (int i = 0; i < numRounds; i++) {
            int sum = rollDie(6) + rollDie(6);
            if (sum == targetSum) {
                hits++;
            }
        }
        return (int)((double) hits / numRounds * 100);
    }
}

