import java.util.ArrayList;

public class Announcement {
    private String text;

    public Announcement(String t) { text = t; }

    public String getText() { return text; }

    public int longestWordLength() {
        if (text.length() == 0) {
            return 0;
        }
        int longest = 0;
        String remaining = text;
        int space = remaining.indexOf(" ");
        while (space != -1) {
            String word = remaining.substring(0, space);
            if (word.length() > longest) {
                longest = word.length();
            }
            remaining = remaining.substring(space + 1);
            space = remaining.indexOf(" ");
        }
        if (remaining.length() > longest) {
            longest = remaining.length();
        }
        return longest;
    }

    public static int countLongAnnouncements(ArrayList<Announcement> list, int minLen) {
        int count = 0;
        for (int i = 0; i < list.size(); i++) {
            Announcement a = list.get(i);
            if (a.longestWordLength() >= minLen) {
                count++;
            }
        }
        return count;
    }
}

