public class Librarian {
    private String name;
    private int numSimulations;

    public Librarian(String n, int sims) {
        name = n;
        numSimulations = sims;
    }

    public int randomLateDays(int minDays, int maxDays) {
        return (int)(Math.random() * (maxDays - minDays + 1)) + minDays;
    }

    public int percentOver(int threshold) {
        if (numSimulations == 0) return 0;
        int count = 0;
        for (int i = 0; i < numSimulations; i++) {
            int days = randomLateDays(0, 14);
            if (days > threshold) {
                count++;
            }
        }
        return (int)((double) count / numSimulations * 100);
    }
}

