public class MessageFilter {
    private String bannedLetter;

    public MessageFilter(String b) {
        bannedLetter = b;
    }

    public boolean containsBanned(String word) {
        for (int i = 0; i < word.length(); i++) {
            if (word.substring(i, i + 1).equals(bannedLetter)) {
                return true;
            }
        }
        return false;
    }

    public int countFlagged(String comment) {
        int count = 0;
        String rest = comment;
        int space = rest.indexOf(" ");
        while (space != -1) {
            String w = rest.substring(0, space);
            if (containsBanned(w)) {
                count++;
            }
            rest = rest.substring(space + 1);
            space = rest.indexOf(" ");
        }
        if (containsBanned(rest)) {
            count++;
        }
        return count;
    }
}
